import{c as o,Q as e,j as a,m as n}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"方块的三层:Block、BlockState 与方块实体","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/09-方块的三层-Block-BlockState与方块实体.md","filePath":"minecraftLearning/09-方块的三层-Block-BlockState与方块实体.md","lastUpdated":1781674740000}'),s={name:"minecraftLearning/09-方块的三层-Block-BlockState与方块实体.md"};function l(r,t,c,d,i,p){return e(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="方块的三层-block、blockstate-与方块实体" tabindex="-1">方块的三层:Block、BlockState 与方块实体 <a class="header-anchor" href="#方块的三层-block、blockstate-与方块实体" aria-label="Permalink to &quot;方块的三层:Block、BlockState 与方块实体&quot;">​</a></h1><p>你在世界里挖到的那块石头,在引擎眼里其实不是&quot;一个对象&quot;。如果你以为&quot;每个方块格子里都装着一个方块对象,里面存着它的种类、朝向、坐标&quot;,那你会立刻撞上一个算术问题:一个加载区不到一百万个方块,一整个世界几十上百亿个方块,每个都装一个带字段的对象,内存和硬盘瞬间就炸了。</p><p>Minecraft 的答案是把&quot;方块&quot;这个看似单一的概念<strong>拆成三层</strong>,每一层解决不同的问题。理解了这三层的分工,你才能解释一连串反直觉现象:为什么千万个石头不占什么内存、为什么箱子里的物品能存住而石头里什么都存不了、为什么床这种平平无奇的方块居然是&quot;方块实体&quot;。</p><blockquote><p>一句话先记住:<strong><code>Block</code> 是种类(单例,定义行为),<code>BlockState</code> 是带属性的具体状态(不可变、可共享、有全局编号),<code>BlockEntity</code> 是少数方块才有的逐实例附加数据</strong>。绝大多数方块只用到前两层,而前两层里没有一个字节是&quot;逐格子私有&quot;的。</p></blockquote><hr><h2 id="一、block-种类与行为-全游戏一个实例" tabindex="-1">一、Block:种类与行为,全游戏一个实例 <a class="header-anchor" href="#一、block-种类与行为-全游戏一个实例" aria-label="Permalink to &quot;一、Block:种类与行为,全游戏一个实例&quot;">​</a></h2><p><code>Block</code> 是一个<strong>类型</strong>。全游戏里&quot;石头&quot;只有一个 <code>Blocks.STONE</code> 对象,世界里千万个石头格子<strong>共享</strong>这同一个对象。它只回答&quot;这一类方块怎么表现&quot;:</p><ul><li>硬度(挖多久)、爆炸抗性</li><li>碰撞箱形状、是否透光、是否可燃</li><li>被破坏时掉落什么</li><li>能不能被随机刻 tick(作物能,石头不能)</li><li>被邻居更新时怎么反应(<code>neighborChanged</code>)</li></ul><p>关键在于它<strong>不存任何&quot;某一个具体位置的石头&quot;的信息</strong>。位置在哪?——位置是它在 section 数组里的<strong>下标隐含表达</strong>的,不需要存在方块对象里。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>朴素心智(错):       引擎实际(对):</span></span>
<span class="line"><span>每格一个对象          Blocks.STONE  ← 唯一一个,所有石头共享</span></span>
<span class="line"><span>{ type:石头,         section 数组下标 = 位置(隐含)</span></span>
<span class="line"><span>  x,y,z, 朝向… }     格子里只放&quot;指向哪个状态&quot;的一个小整数</span></span></code></pre></div><p>所以 <code>Block</code> 是&quot;类&quot;,不是&quot;实例&quot;。把它想成 Java 里的 <code>Class</code> 对象就对了:描述行为,不描述某个具体个体。</p><hr><h2 id="二、blockstate-带属性的状态-可共享、有全局编号" tabindex="-1">二、BlockState:带属性的状态,可共享、有全局编号 <a class="header-anchor" href="#二、blockstate-带属性的状态-可共享、有全局编号" aria-label="Permalink to &quot;二、BlockState:带属性的状态,可共享、有全局编号&quot;">​</a></h2><p>光有&quot;种类&quot;不够。同一种方块有不同<strong>状态</strong>:楼梯朝哪、半砖在上还是在下、红石线几格电、作物长到第几阶段、方块里有没有灌水。</p><p><code>BlockState</code> = <code>Block</code> + 一组<strong>属性(property)</strong> 的取值:</p><table tabindex="0"><thead><tr><th>方块</th><th>典型属性</th><th>取值</th></tr></thead><tbody><tr><td>楼梯</td><td><code>facing</code> / <code>half</code> / <code>shape</code> / <code>waterlogged</code></td><td>4 × 2 × 5 × 2 = 80 种</td></tr><tr><td>红石线</td><td><code>power</code> + 各方向连接形态</td><td>0–15 等</td></tr><tr><td>作物</td><td><code>age</code></td><td>0–7</td></tr><tr><td>树叶</td><td><code>distance</code> / <code>persistent</code></td><td>离树干多远 / 是否人工放置</td></tr><tr><td>任意可灌水方块</td><td><code>waterlogged</code></td><td>true / false</td></tr></tbody></table><p>每一种属性取值组合 = <strong>一个独立的 BlockState</strong>。橡木楼梯就有 80 个 BlockState。</p><h3 id="全局调色板-给所有状态编号" tabindex="-1">全局调色板:给所有状态编号 <a class="header-anchor" href="#全局调色板-给所有状态编号" aria-label="Permalink to &quot;全局调色板:给所有状态编号&quot;">​</a></h3><p>游戏启动时,把所有方块的所有 BlockState 组合<strong>枚举一遍、编上全局数字 ID</strong>,形成一张全局表(目前两万多个 BlockState)。</p><p>最关键的性质:<strong>BlockState 是不可变(immutable)、可共享(interned)的</strong>。世界里所有&quot;朝东、含水、上半&quot;的橡木楼梯,指向的是<strong>同一个 BlockState 对象</strong>,不是各存一份。</p><p>这就解释了上一章 palette 为什么能极致压缩:</p><blockquote><p>因为方块<strong>没有逐实例数据</strong>,存一个方块只需要存&quot;它指向全局表里哪个 BlockState 的下标&quot;。一段全是石头的区域,4096 个格子指向的是同一个下标——局部调色板里只有一项,几乎不占空间。</p></blockquote><p>一句话:<strong>Block 是类,BlockState 是这个类的&quot;枚举值&quot;,二者都是单例级别的共享对象,世界里逐格存的只是一个指向它们的小整数。</strong></p><hr><h2 id="三、blockentity-少数方块的逐实例附加数据" tabindex="-1">三、BlockEntity:少数方块的逐实例附加数据 <a class="header-anchor" href="#三、blockentity-少数方块的逐实例附加数据" aria-label="Permalink to &quot;三、BlockEntity:少数方块的逐实例附加数据&quot;">​</a></h2><p>问题来了:箱子里装了什么?告示牌写了什么字?熔炉烧到第几秒?这些是<strong>每个具体位置都不同的数据</strong>,塞不进&quot;可共享的 BlockState&quot;——你总不能给&quot;装着 3 个钻石的箱子&quot;和&quot;装着 1 把剑的箱子&quot;各开一个全局 BlockState。</p><p>于是有了<strong>方块实体 <code>BlockEntity</code></strong>(老译名&quot;tile entity&quot;):</p><ul><li>只有<strong>少数需要额外数据的方块</strong>才有:箱子、熔炉、告示牌、刷怪笼、信标、漏斗、命令方块……普通石头、泥土、楼梯<strong>没有</strong>。</li><li>它<strong>绑定到一个具体坐标</strong>,逐实例存在,数据用 <strong>NBT</strong> 序列化。</li><li>部分方块实体<strong>每 tick 更新</strong>(熔炉烧炼、漏斗搬运),这就是主循环里 <code>tickBlockEntities</code> 遍历的对象,也是它们贵的原因。</li></ul><p>所以一个箱子方块 = <strong>BlockState(朝向、是否含水,共享)</strong> + <strong>BlockEntity(里面的物品 NBT,私有)</strong> 两部分拼起来。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>普通方块(石头):   BlockState 下标   ……就这些</span></span>
<span class="line"><span>箱子方块:          BlockState 下标(朝向/含水)</span></span>
<span class="line"><span>                 + BlockEntity NBT(Items 列表、自定义名…)← 逐实例</span></span></code></pre></div><p>到这里,&quot;只有需要存额外数据的方块才有方块实体&quot;这个印象看起来很自洽。但下面这个例子会把它打破。</p><hr><h2 id="四、床-一个几乎不存数据、却是方块实体的反例" tabindex="-1">四、床:一个几乎不存数据、却是方块实体的反例 <a class="header-anchor" href="#四、床-一个几乎不存数据、却是方块实体的反例" aria-label="Permalink to &quot;四、床:一个几乎不存数据、却是方块实体的反例&quot;">​</a></h2><p>床是方块实体——这是真的,而且它是个特别有意思的&quot;反例&quot;。</p><p>回想普通方块实体:箱子存物品、熔炉存进度,都是实打实的玩法数据。床呢?它的功能数据<strong>根本不需要方块实体</strong>:</p><table tabindex="0"><thead><tr><th>床的状态</th><th>存在哪</th></tr></thead><tbody><tr><td>朝向(头朝哪)</td><td>BlockState <code>facing</code></td></tr><tr><td>床头还是床尾</td><td>BlockState <code>part = head / foot</code></td></tr><tr><td>有没有人睡</td><td>BlockState <code>occupied</code></td></tr><tr><td>重生点设定</td><td>玩家数据 + 床方块的<strong>行为逻辑</strong>,与方块实体无关</td></tr><tr><td>颜色</td><td>每种颜色是<strong>独立的方块</strong>(16 种 <code>*_bed</code>),在方块种类里</td></tr></tbody></table><p>你会发现:<strong>床的所有玩法状态都进了 BlockState,没有一样非得放方块实体。</strong> 那它为什么还有?</p><h3 id="真正原因-渲染" tabindex="-1">真正原因:渲染 <a class="header-anchor" href="#真正原因-渲染" aria-label="Permalink to &quot;真正原因:渲染&quot;">​</a></h3><p>床有方块实体,主要是为了挂一个<strong>专用渲染器(<code>BlockEntityRenderer</code>,旧称 TileEntitySpecialRenderer)</strong>。</p><p>普通方块用标准&quot;方块模型系统&quot;渲染——本质是一堆带贴图的立方体面,静态、简单。但床那个带床头床尾、布料质感、四条小腿的 3D 模型,超出了标准模型系统的表达能力,得用代码写一个专门渲染器逐个绘制,而<strong>挂这个渲染器需要方块有一个 BlockEntity 当锚点</strong>。</p><p>所以床的方块实体里那点数据基本是<strong>给渲染器看的</strong>,不是给玩法逻辑用的。由此得到一条更准确的判据:</p><blockquote><p>一个方块在<strong>需要逐实例数据</strong>,<strong>或需要标准模型系统画不出来的特殊渲染/动画</strong>时,会带一个方块实体。床命中的是后半句。</p></blockquote><p>这类&quot;为渲染而存在&quot;的方块实体不少:箱子(开盖动画)、告示牌(文字)、旗帜、头颅、潜影盒、唱片机、钟、信标光柱、海晶灯……它们分两类驱动力——存逐实例数据、或需要专用渲染器——很多两者兼有,而床几乎是纯第二类。</p><hr><h2 id="五、箱子-把两类职责合在一起的满分例子" tabindex="-1">五、箱子:把两类职责合在一起的满分例子 <a class="header-anchor" href="#五、箱子-把两类职责合在一起的满分例子" aria-label="Permalink to &quot;五、箱子:把两类职责合在一起的满分例子&quot;">​</a></h2><p>床是&quot;纯渲染型&quot;,箱子则<strong>两类职责全占</strong>,还多出一个难点:两个方块实体怎么合并成一个大箱子。</p><h3 id="_1-数据职责-存物品" tabindex="-1">1. 数据职责:存物品 <a class="header-anchor" href="#_1-数据职责-存物品" aria-label="Permalink to &quot;1. 数据职责:存物品&quot;">​</a></h3><p><code>ChestBlockEntity</code> 内部是一个定长列表,普通箱子 <strong>27 个槽</strong>,每槽一个 ItemStack。存盘序列化成 <code>Items</code> 列表:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Items: [</span></span>
<span class="line"><span>  { Slot: 0, id: &quot;minecraft:diamond_sword&quot;, count: 1, components:{…} },</span></span>
<span class="line"><span>  { Slot: 5, id: &quot;minecraft:torch&quot;, count: 64 }</span></span>
<span class="line"><span>]</span></span></code></pre></div><p>注意<strong>空槽不写</strong>——只放了两组物品的箱子,<code>Items</code> 就两个元素,省空间。</p><h3 id="_2-战利品箱的-懒生成" tabindex="-1">2. 战利品箱的&quot;懒生成&quot; <a class="header-anchor" href="#_2-战利品箱的-懒生成" aria-label="Permalink to &quot;2. 战利品箱的&quot;懒生成&quot;&quot;">​</a></h3><p>地牢/沉船里的箱子,在你打开前其实是空的。它的方块实体不存物品,而是存:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LootTable: &quot;minecraft:chests/simple_dungeon&quot;   ← 用哪张战利品表</span></span>
<span class="line"><span>LootTableSeed: &lt;随机种子&gt;</span></span></code></pre></div><p><strong>第一次被打开</strong>时,才用这张表 + 这个种子现场生成物品,然后清掉这两个字段。好处:成千上万个未探索的箱子不预存物品,只存&quot;配方 + 种子&quot;两个值——这是&quot;能算出来的就不存&quot;这条主线在物品层的复用,和地形用种子生成同理。</p><h3 id="_3-渲染职责-开盖动画" tabindex="-1">3. 渲染职责:开盖动画 <a class="header-anchor" href="#_3-渲染职责-开盖动画" aria-label="Permalink to &quot;3. 渲染职责:开盖动画&quot;">​</a></h3><p>箱子用专用渲染器,读一个 <strong>0.0–1.0 的开合度</strong>把盖子绕铰链旋转画出来。这个值由 <strong><code>ChestLidController</code></strong> 管理:它有&quot;当前开合度&quot;和&quot;目标值&quot;,<strong>每 tick 朝目标插值逼近</strong>,所以盖子是平滑掀开而非瞬间。因此箱子注册了一个 ticker——但这个动画 tick 很轻,和漏斗那种&quot;每 tick 查容器&quot;的重 tick 不是一回事。</p><h3 id="_4-盖子怎么知道该开-观察者计数" tabindex="-1">4. 盖子怎么知道该开:观察者计数 <a class="header-anchor" href="#_4-盖子怎么知道该开-观察者计数" aria-label="Permalink to &quot;4. 盖子怎么知道该开:观察者计数&quot;">​</a></h3><p>开合靠 <strong><code>ContainerOpenersCounter</code></strong> 记录&quot;当前有几个玩家正打开着它&quot;:</p><ul><li>计数 <strong>0 → 1</strong>(第一个人打开):播放开箱音效、目标设为&quot;开&quot;</li><li>计数 <strong>1 → 0</strong>(最后一个人关闭):播放关箱音效、目标设为&quot;关&quot;</li><li>中间来来去去(2→3→2)不重复播音效</li></ul><p>这就是为什么多人同时开同一个箱子盖子只开一次;也是为什么箱子上方放方块会卡住打不开——开盖判定里会检查盖子上方有没有障碍。</p><h3 id="_5-大箱子-两个方块实体怎么变成一个" tabindex="-1">5. 大箱子:两个方块实体怎么变成一个 <a class="header-anchor" href="#_5-大箱子-两个方块实体怎么变成一个" aria-label="Permalink to &quot;5. 大箱子:两个方块实体怎么变成一个&quot;">​</a></h3><p>两个并排、同朝向的箱子合成 54 格大箱子,但底层<strong>始终是两个独立方块、两个独立方块实体</strong>,只是在逻辑和渲染两层被<strong>临时配对</strong>:</p><ul><li><strong>BlockState 标左右</strong>:箱子有属性 <code>type = single | left | right</code>。放下第二个箱子时,通过邻居更新两个箱子各自变成 <code>left</code> / <code>right</code>。<strong>配对关系由 BlockState 表达,不在方块实体里</strong>——所以中间打断,靠 BlockState 重算就拆开了。</li><li><strong>背包合并</strong>:打开时临时创建一个 <strong><code>CompoundContainer</code></strong> 把两个 27 格拼成 54 格的<strong>视图</strong>,槽 0–26 路由到左箱、27–53 路由到右箱。<strong>物品始终分存在两个方块实体里</strong>,从没真合并;拆掉一半,另一半的 27 格原封不动还在它自己的方块实体里。</li><li><strong>渲染合并</strong>:<code>DoubleBlockCombiner</code> 根据 <code>type</code> 和 <code>facing</code> 找到相邻的另一半,渲染器据此选正确的半边模型拼成无缝大箱子,并用共享的盖子控制器让两半盖子<strong>同步掀开</strong>。</li></ul><blockquote><p>一句话:大箱子是&quot;两个真实方块实体 + BlockState 标左右 + 打开/渲染时临时配对成一个视图&quot;的产物。底层永远是二,体验上是一。</p></blockquote><hr><h2 id="六、踩坑与反直觉" tabindex="-1">六、踩坑与反直觉 <a class="header-anchor" href="#六、踩坑与反直觉" aria-label="Permalink to &quot;六、踩坑与反直觉&quot;">​</a></h2><ul><li><strong>&quot;每个方块都是对象&quot;是错的。</strong> 绝大多数方块在世界里只是一个指向共享 BlockState 的小整数,没有逐实例对象。只有那批进了方块实体白名单的方块,才在该坐标真正 new 出一个 BlockEntity。</li><li><strong>&quot;方块实体 = 存东西&quot;不全对。</strong> 床、唱片机这类的方块实体核心职责是渲染,几乎不存玩法数据。判据是&quot;逐实例数据 <strong>或</strong> 特殊渲染&quot;。</li><li><strong>大箱子不是一个对象。</strong> 它永远是两个方块实体,只在打开/渲染时被包装成一个视图。很多人以为大箱子内部合并了,其实拆开时数据各归各家正是因为从没合并过。</li><li><strong>方块实体有运行成本。</strong> <code>tickBlockEntities</code> 要逐个遍历有 ticker 的方块实体,这是漏斗物流卡服的根源。也正因如此,新设计倾向于&quot;宁愿堆 BlockState 也不加方块实体&quot;。</li></ul><hr><h2 id="七、串联" tabindex="-1">七、串联 <a class="header-anchor" href="#七、串联" aria-label="Permalink to &quot;七、串联&quot;">​</a></h2><ul><li><strong>承接上一章(存储/Palette)</strong>:本章解释了 palette 为什么能压到极致——因为 Block 与 BlockState 都是共享的不可变对象,方块<strong>无逐实例数据</strong>,逐格存的只是调色板下标。方块实体则是 palette 装不下的那部分,单独走 NBT 落进 chunk 的 <code>block_entities</code> 列表。</li><li><strong>对照&quot;实体&quot;那一章</strong>:方块实体名字里带&quot;实体&quot;,本质却是<strong>方块的一部分</strong>(绑定网格坐标),和能脱离网格自由移动、每个都 tick 的 <code>Entity</code> 是两套系统。下一步对比&quot;床头朝向(BlockState) → 箱子物品(BlockEntity) → 掉地上的剑(Entity)&quot;会更清楚。</li><li><strong>指向&quot;还有什么&quot;那一章</strong>:方块这一层之外,同一个坐标上其实还叠着流体(FluidState)和光照,物品又是另一类寄生数据——下一章把这些平行的对象类别一次铺开。</li></ul><p>记住这三层的分工,你就拿到了读懂 Minecraft 数据模型的第一把钥匙:<strong>Block 定义&quot;这是什么&quot;,BlockState 定义&quot;它什么样&quot;(共享),BlockEntity 补上&quot;这一个里装了什么&quot;(私有)。</strong></p>`,71)])])}const h=o(s,[["render",l]]);export{g as __pageData,h as default};
